namespace TicketClassifier.Models;

public class TicketRequest
{
    public string Subject { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public int Priority { get; set; }
}

public class TicketPredictionResponse
{
    public string PredictedCategory { get; set; } = string.Empty;
    public Dictionary<string, float> Scores { get; set; } = new();
}

using Microsoft.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Services;

public class ModelTrainingService
{
    private readonly MLContext _mlContext;
    private readonly ILogger<ModelTrainingService> _logger;
    private readonly string _dataPath;
    private readonly string _modelPath;

    public ModelTrainingService(ILogger<ModelTrainingService> logger, IWebHostEnvironment env)
    {
        _mlContext = new MLContext(seed: 42);
        _logger = logger;
        _dataPath = Path.Combine(env.ContentRootPath, "Data", "tickets.csv");
        _modelPath = Path.Combine(env.ContentRootPath, "Data", "model.zip");
    }

    public string ModelPath => _modelPath;

    public void TrainAndEvaluate()
    {
        _logger.LogInformation("Loading training data from {Path}", _dataPath);

        var data = _mlContext.Data.LoadFromTextFile<TicketInput>(
            _dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        var split = _mlContext.Data.TrainTestSplit(data, testFraction: 0.2, seed: 42);

        var pipeline = _mlContext.Transforms.Text.FeaturizeText("SubjectFeatures", nameof(TicketInput.Subject))
            .Append(_mlContext.Transforms.Text.FeaturizeText("DescriptionFeatures", nameof(TicketInput.Description)))
            .Append(_mlContext.Transforms.Concatenate("Features", "SubjectFeatures", "DescriptionFeatures", nameof(TicketInput.Priority)))
            .Append(_mlContext.Transforms.Conversion.MapValueToKey("Label", nameof(TicketInput.Category)))
            .Append(_mlContext.MulticlassClassification.Trainers.SdcaMaximumEntropy("Label", "Features"))
            .Append(_mlContext.Transforms.Conversion.MapKeyToValue("PredictedLabel"));

        _logger.LogInformation("Training model...");
        var model = pipeline.Fit(split.TrainSet);

        _logger.LogInformation("Evaluating model...");
        var predictions = model.Transform(split.TestSet);
        var metrics = _mlContext.MulticlassClassification.Evaluate(predictions);

        _logger.LogInformation("===== Model Evaluation Metrics =====");
        _logger.LogInformation("MacroAccuracy:    {MacroAccuracy:F4}", metrics.MacroAccuracy);
        _logger.LogInformation("MicroAccuracy:    {MicroAccuracy:F4}", metrics.MicroAccuracy);
        _logger.LogInformation("LogLoss:          {LogLoss:F4}", metrics.LogLoss);
        _logger.LogInformation("LogLossReduction: {LogLossReduction:F4}", metrics.LogLossReduction);

        // Retrain on full dataset for production model
        _logger.LogInformation("Retraining on full dataset for production model...");
        var productionModel = pipeline.Fit(data);

        _mlContext.Model.Save(productionModel, data.Schema, _modelPath);
        _logger.LogInformation("Model saved to {Path}", _modelPath);
    }
}

using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/[controller]")]
public class TicketClassifierController : ControllerBase
{
    private readonly PredictionEnginePool<TicketInput, TicketPrediction> _predictionPool;
    private static readonly string[] Categories = ["Billing", "Technical", "General"];

    public TicketClassifierController(PredictionEnginePool<TicketInput, TicketPrediction> predictionPool)
    {
        _predictionPool = predictionPool;
    }

    [HttpPost("predict")]
    public ActionResult<TicketPredictionResponse> Predict([FromBody] TicketRequest request)
    {
        if (string.IsNullOrWhiteSpace(request.Subject) && string.IsNullOrWhiteSpace(request.Description))
        {
            return BadRequest("Subject or Description must be provided.");
        }

        if (request.Priority < 1 || request.Priority > 3)
        {
            return BadRequest("Priority must be between 1 and 3.");
        }

        var input = new TicketInput
        {
            Subject = request.Subject,
            Description = request.Description,
            Priority = request.Priority
        };

        var prediction = _predictionPool.Predict(input);

        var scores = new Dictionary<string, float>();
        for (int i = 0; i < prediction.Score.Length && i < Categories.Length; i++)
        {
            scores[Categories[i]] = prediction.Score[i];
        }

        return Ok(new TicketPredictionResponse
        {
            PredictedCategory = prediction.PredictedCategory,
            Scores = scores
        });
    }
}

